Here's a solid pattern using `MockHttpMessageHandler` and MSTest's async support:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Helper: injectable mock handler
    private static HttpClient CreateMockClient(
        Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> handler)
    {
        return new HttpClient(new MockHandler(handler));
    }

    private class MockHandler(
        Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> handler)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken ct) => handler(request, ct);
    }

    // 1. Happy path
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        using var client = CreateMockClient((_, _) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.OK)
            {
                Content = new StringContent("hello")
            }));

        var fetcher = new DataFetcher(client);
        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    // 2. HTTP error throws
    [TestMethod]
    public async Task FetchAsync_Throws_OnHttpError()
    {
        using var client = CreateMockClient((_, _) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.InternalServerError)));

        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // 3. Cancellation is respected
    [TestMethod]
    public async Task FetchAsync_Throws_WhenCancelled()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        using var client = CreateMockClient((_, ct) =>
        {
            ct.ThrowIfCancellationRequested();
            return Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.OK));
        });

        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // 4. Timeout via CancellationTokenSource
    [TestMethod]
    public async Task FetchAsync_Throws_OnTimeout()
    {
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        using var client = CreateMockClient(async (_, ct) =>
        {
            await Task.Delay(TimeSpan.FromSeconds(10), ct); // simulate slow server
            return new HttpResponseMessage(System.Net.HttpStatusCode.OK);
        });

        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // 5. MSTest-level safety net via [Timeout]
    [TestMethod]
    [Timeout(3000)] // fails test if it hangs beyond 3s
    public async Task FetchAsync_DoesNotHang()
    {
        using var client = CreateMockClient((_, _) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.OK)
            {
                Content = new StringContent("ok")
            }));

        var fetcher = new DataFetcher(client);
        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("ok", result);
    }
}
```

**Key patterns:**

| Technique | Purpose |
|---|---|
| `MockHttpMessageHandler` | Avoids real HTTP; controls responses at the `HttpClient` layer |
| `CancellationTokenSource` with pre-cancel | Tests that the token is actually forwarded |
| `CancellationTokenSource(TimeSpan)` | Simulates a timeout without waiting forever |
| `[Timeout(ms)]` | MSTest safety net — kills truly stuck tests |
| `Assert.ThrowsExceptionAsync` | Proper async exception assertion (never use `.Result` or `.Wait()`) |

**Common pitfall to avoid:** Don't use `Task.Result` or `.GetAwaiter().GetResult()` in tests — it deadlocks on synchronization contexts. Always use `async Task` test methods with `await`.
